exercises.solution:
async function getFilteredPosts(prisma, options = {}) {
  const { published, authorId, search, page = 1, pageSize = 10 } = options;
  const where = {};

  if (published !== undefined) where.published = published;
  if (authorId !== undefined) where.authorId = authorId;
  if (search) {
    where.OR = [
      { title: { contains: search, mode: 'insensitive' } },
      { content: { contains: search, mode: 'insensitive' } }
    ];
  }

  const posts = await prisma.post.findMany({
    where,
    include: { author: { select: { name: true } } },
    orderBy: { createdAt: 'desc' },
    skip: (page - 1) * pageSize,
    take: pageSize
  });

  console.log('Query where:', JSON.stringify(where));
  console.log('Page:', page, 'Size:', pageSize);
  return posts;
}

