class ProductRepository {
  constructor(db) {
    this.db = db;
  }

  findAll() {
    return this.db.products;
  }

  findById(id) {
    return this.db.products.find(p => p.id === id) || null;
  }

  create(product) {
    const newProduct = { id: this.db.nextId++, ...product };
    this.db.products.push(newProduct);
    return newProduct;
  }

  deleteById(id) {
    const index = this.db.products.findIndex(p => p.id === id);
    if (index === -1) return false;
    this.db.products.splice(index, 1);
    return true;
  }
}

